+            call_args,
+            payload,
+            project_hint,
+            agent_hint,
+            atc_db_pool,
+        ),
+        "release_build_slot" => record_release_build_slot_observation(
+            call_args,
+            payload,
+            project_hint,
+            agent_hint,
+            atc_db_pool,
+        ),
+        _ => {}
+    }
